<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>N.VAN // MAZDA3 HATCHBACKS</title>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Oswald:wght@500;700&family=Exo+2:ital,wght@0,300;0,500;0,700;1,300&display=swap" rel="stylesheet">
    <style>
        :root {
            --bg-base: #050505;
            --bg-surface: #121212;
            --bg-surface-hover: #1a1a1a;
            --accent-red: #d90429;
            --accent-red-glow: rgba(217, 4, 41, 0.4);
            --text-main: #fdfdfd;
            --text-muted: #8d99ae;
            --border-color: #2b2d42;
        }

        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
        }

        body {
            font-family: 'Exo 2', sans-serif;
            background-color: var(--bg-base);
            color: var(--text-main);
            background-image: 
                radial-gradient(circle at 15% 50%, rgba(217, 4, 41, 0.05), transparent 25%),
                radial-gradient(circle at 85% 30%, rgba(43, 45, 66, 0.2), transparent 25%);
            background-attachment: fixed;
            min-height: 100vh;
            overflow-x: hidden;
        }

        /* Noise overlay */
        body::before {
            content: "";
            position: fixed;
            top: 0; left: 0; width: 100vw; height: 100vh;
            background: url('data:image/svg+xml;utf8,%3Csvg viewBox="0 0 200 200" xmlns="http://www.w3.org/2000/svg"%3E%3Cfilter id="noiseFilter"%3E%3CfeTurbulence type="fractalNoise" baseFrequency="0.85" numOctaves="3" stitchTiles="stitch"/%3E%3C/filter%3E%3Crect width="100%25" height="100%25" filter="url(%23noiseFilter)" opacity="0.03"/%3E%3C/svg%3E');
            pointer-events: none;
            z-index: 999;
        }

        header {
            padding: 6rem 2rem 4rem;
            position: relative;
            border-bottom: 1px solid var(--border-color);
            background: linear-gradient(180deg, rgba(5,5,5,0.9) 0%, rgba(18,18,18,0.4) 100%);
            backdrop-filter: blur(10px);
        }

        .header-content {
            max-width: 1400px;
            margin: 0 auto;
            position: relative;
        }

        .header-badge {
            display: inline-block;
            font-family: 'Oswald', sans-serif;
            text-transform: uppercase;
            letter-spacing: 3px;
            font-size: 0.8rem;
            color: var(--accent-red);
            margin-bottom: 1rem;
            border: 1px solid var(--accent-red);
            padding: 0.3rem 0.8rem;
            border-radius: 2px;
        }

        h1 {
            font-family: 'Oswald', sans-serif;
            font-size: clamp(3rem, 8vw, 6rem);
            line-height: 1;
            text-transform: uppercase;
            letter-spacing: -1px;
            margin-bottom: 1rem;
            background: linear-gradient(to right, #fff, #8d99ae);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
        }

        header p {
            font-size: 1.2rem;
            color: var(--text-muted);
            max-width: 600px;
            font-weight: 300;
        }

        .grid-container {
            max-width: 1400px;
            margin: 4rem auto;
            padding: 0 2rem;
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(400px, 1fr));
            gap: 2.5rem;
        }

        .card {
            background: var(--bg-surface);
            border: 1px solid var(--border-color);
            border-radius: 4px;
            position: relative;
            transition: all 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94);
            display: flex;
            flex-direction: column;
            opacity: 0;
            transform: translateY(30px);
            animation: fadeUp 0.8s forwards;
        }

        .card:nth-child(1) { animation-delay: 0.1s; }
        .card:nth-child(2) { animation-delay: 0.2s; }
        .card:nth-child(3) { animation-delay: 0.3s; }
        .card:nth-child(4) { animation-delay: 0.4s; }
        .card:nth-child(5) { animation-delay: 0.5s; }

        @keyframes fadeUp {
            to {
                opacity: 1;
                transform: translateY(0);
            }
        }

        .card::before {
            content: '';
            position: absolute;
            top: 0; left: 0; width: 100%; height: 100%;
            background: radial-gradient(800px circle at var(--mouse-x, 50%) var(--mouse-y, 50%), rgba(217, 4, 41, 0.06), transparent 40%);
            z-index: 0;
            pointer-events: none;
            opacity: 0;
            transition: opacity 0.3s;
        }

        .card:hover {
            transform: translateY(-10px);
            border-color: var(--accent-red);
            box-shadow: 0 20px 40px rgba(0,0,0,0.5), 0 0 20px var(--accent-red-glow);
        }

        .card:hover::before {
            opacity: 1;
        }

        .card-content {
            position: relative;
            z-index: 1;
            padding: 2.5rem;
            flex-grow: 1;
            display: flex;
            flex-direction: column;
        }

        .source-tag {
            font-family: 'Oswald', sans-serif;
            font-size: 0.75rem;
            letter-spacing: 2px;
            color: var(--text-muted);
            text-transform: uppercase;
            margin-bottom: 1rem;
            display: flex;
            align-items: center;
            gap: 8px;
        }

        .source-tag::before {
            content: '';
            display: block;
            width: 12px;
            height: 2px;
            background-color: var(--accent-red);
        }

        .card h2 {
            font-family: 'Oswald', sans-serif;
            font-size: 2rem;
            line-height: 1.1;
            margin-bottom: 0.5rem;
            text-transform: uppercase;
        }

        .price {
            font-family: 'Oswald', sans-serif;
            font-size: 2.5rem;
            color: var(--accent-red);
            margin-bottom: 2rem;
            display: flex;
            align-items: baseline;
            gap: 5px;
        }

        .price small {
            font-size: 1rem;
            color: var(--text-muted);
            font-family: 'Exo 2', sans-serif;
        }

        .specs {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 1.5rem;
            margin-bottom: 2rem;
        }

        .spec-item {
            display: flex;
            flex-direction: column;
            gap: 4px;
        }

        .spec-label {
            font-size: 0.75rem;
            text-transform: uppercase;
            letter-spacing: 1px;
            color: var(--text-muted);
